public function resolveRouteBindingQuery($query, $value, $field = null)
    {
        if ($field && in_array($field, $this->uniqueIds()) && ! $this->isValidUniqueId($value)) {
            $this->handleInvalidUniqueId($value, $field);
        }

        if (! $field && in_array($this->getRouteKeyName(), $this->uniqueIds()) && ! $this->isValidUniqueId($value)) {
            $this->handleInvalidUniqueId($value, $field);
        }

        return parent::resolveRouteBindingQuery($query, $value, $field);
    }

public function persistNewAccessToken(AccessTokenEntityInterface $accessTokenEntity): void
    {
        Passport::token()->forceFill([
            'id' => $id = $accessTokenEntity->getIdentifier(),
            'user_id' => $userId = $accessTokenEntity->getUserIdentifier(),
            'client_id' => $clientId = $accessTokenEntity->getClient()->getIdentifier(),
            'scopes' => $accessTokenEntity->getScopes(),
            'revoked' => false,
            'expires_at' => $accessTokenEntity->getExpiryDateTime(),
        ])->save();

        $this->events->dispatch(new AccessTokenCreated($id, $userId, $clientId));
    }

public function fill($values)
    {
        $publicProperties = array_keys($this->all());

        if ($values instanceof Model) {
            $values = $values->toArray();
        }

        foreach ($values as $key => $value) {
            if (in_array(Utils::beforeFirstDot($key), $publicProperties)) {
                data_set($this, $key, $value);
            }
        }
    }

public function mount($params)
    {
        if (store($this->component)->has('skipMount')) { return; }

        $this->callHook('boot');
        $this->callTraitHook('boot');

        $this->callTraitHook('initialize');

        $this->callHook('mount', $params);
        $this->callTraitHook('mount', $params);

        $this->callHook('booted');
        $this->callTraitHook('booted');
    }

public function callHook($name, $params = [])
    {
        // Performance optimization: Cache method existence checks
        $class = get_class($this->component);
        $cacheKey = "{$class}::{$name}";

        if (!isset(static::$methodCache[$cacheKey])) {
            static::$methodCache[$cacheKey] = method_exists($this->component, $name);
        }

        if (static::$methodCache[$cacheKey]) {
            wrap($this->component)->__call($name, $params);
        }
    }

foreach ($models as $key => $model) {
    if ($model->{$this->morphType}) {
        $morphTypeKey = $this->getDictionaryKey($model->{$this->morphType});
        $foreignKeyKey = $this->getDictionaryKey($model->{$this->foreignKey});

        if ($morphTypeKey === null || $foreignKeyKey === null) {
            continue;
        }

        if ($isAssociative) {
            $this->dictionary[$morphTypeKey][$foreignKeyKey][$key] = $model;
        } else {
            $this->dictionary[$morphTypeKey][$foreignKeyKey][] = $model;
        }
    }
}

public function withErrors($provider, $key = 'default')
    {
        $value = $this->parseErrors($provider);

        $errors = $this->session->get('errors', new ViewErrorBag);

        if (! $errors instanceof ViewErrorBag) {
            $errors = new ViewErrorBag;
        }

        $this->session->flash(
            'errors', $errors->put($key, $value)
        );

        return $this;
    }

public function enforceSameOrigin(
    string $fallback,
    bool $validateScheme = true,
    bool $validatePort = true,
): static {
    $target = Uri::of($this->targetUrl);
    $current = Uri::of($this->request->getSchemeAndHttpHost());

    if ($target->host() !== $current->host() ||
        ($validateScheme && $target->scheme() !== $current->scheme()) ||
        ($validatePort && $target->port() !== $current->port())) {
        $this->setTargetUrl($fallback);
    }

    return $this;
}

protected function expandConsolidatedFormObjectUpdates($component, $updates)
    {
        $expanded = [];

        foreach ($updates as $path => $value) {
            if (is_array($value) && property_exists($component, $path) && $component->$path instanceof Form) {
                foreach ($value as $key => $child) {
                    $expanded["{$path}.{$key}"] = $child;
                }
            } else {
                $expanded[$path] = $value;
            }
        }

        return $expanded;
    }

